createResponses.python:
from mintlify_demo import MintlifyDemo, models
import os


with MintlifyDemo(
    http_referer="<value>",
    app_title="<value>",
    app_categories="<value>",
    api_key=os.getenv("MINTLIFYDEMO_API_KEY", ""),
) as md_client:

    res = md_client.beta.responses.send(input="Tell me a joke", metadata={
        "user_id": "123",
        "session_id": "abc-def-ghi",
    }, tools=[
        {
            "type": "function",
            "name": "get_weather",
            "description": "Get the current weather in a location",
            "parameters": {
                "type": "object",
                "properties": {
                    "location": {
                        "type": "string",
                        "description": "The city and state",
                    },
                    "unit": {
                        "type": "string",
                        "enum": [
                            "celsius",
                            "fahrenheit",
                        ],
                        "x-speakeasy-unknown-values": "allow",
                    },
                },
                "required": [
                    "location",
                ],
            },
        },
    ], tool_choice="auto", model="openai/gpt-4o", text={
        "format_": {
            "type": "text",
        },
    }, reasoning={
        "summary": "auto",
        "enabled": True,
    }, image_config={
        "aspect_ratio": "16:9",
    }, modalities=[
        "text",
        "image",
    ], prompt={
        "id": "prompt-abc123",
        "variables": {
            "name": "John",
        },
    }, include=[
        "file_search_call.results",
    ], service_tier="auto", truncation="auto", stream=False, provider={
        "allow_fallbacks": True,
    }, plugins=[
        {
            "id": "auto-router",
            "enabled": True,
            "allowed_models": [
                "anthropic/*",
                "openai/gpt-4o",
            ],
        },
    ], trace=models.TraceConfig(
        trace_id="trace-abc123",
        trace_name="my-app-trace",
    ))

    with res as event_stream:
        for event in event_stream:
            # handle event
            print(event, flush=True)

